import React, { useState, useEffect, useRef } from 'react';
import { AppState, SavedModel, VoxelData, EditTool, SymmetryMode, VoxelKeyframe } from '../types';
import { Box, Bird, Cat, Rabbit, Users, Code2, Wand2, Hammer, FolderOpen, ChevronUp, FileJson, History, Play, Pause, Info, Wrench, Loader2, Paintbrush, Eraser, Layers, RotateCcw, Film, Plus, Trash2, Repeat, SkipForward, Sparkles, Grid } from 'lucide-react';
import { COLORS } from '../utils/voxelConstants';

interface UIOverlayProps {
  voxelCount: number;
  appState: AppState;
  currentBaseModel: string;
  customBuilds: SavedModel[];
  customRebuilds: SavedModel[];
  isAutoRotate: boolean;
  isInfoVisible: boolean;
  isGenerating: boolean;
  isWireframe: boolean;

  // Edit Mode Props
  isEditMode: boolean;
  activeTool: EditTool;
  activeColor: number;
  symmetryMode: SymmetryMode;
  onSetEditMode: (val: boolean) => void;
  onSetTool: (tool: EditTool) => void;
  onSetColor: (color: number) => void;
  onSetSymmetry: (mode: SymmetryMode) => void;

  // Animation Props
  keyframes: VoxelKeyframe[];
  currentFrameIndex: number;
  isAnimating: boolean;
  isLooping: boolean;
  onCaptureKeyframe: () => void;
  onDeleteKeyframe: (id: string) => void;
  onJumpToKeyframe: (index: number) => void;
  onTogglePlayback: () => void;
  onToggleLoop: () => void;
  onPromptAnimate: () => void;

  onDismantle: () => void;
  onRebuild: (type: 'Eagle' | 'Cat' | 'Rabbit' | 'Twins') => void;
  onNewScene: (type: 'Eagle') => void;
  onSelectCustomBuild: (model: SavedModel) => void;
  onSelectCustomRebuild: (model: SavedModel) => void;
  onPromptCreate: () => void;
  onPromptMorph: () => void;
  onShowJson: () => void;
  onImportJson: () => void;
  onToggleRotation: () => void;
  onToggleWireframe: () => void;
  onToggleInfo: () => void;
}

const LOADING_MESSAGES = [
    "Crafting voxels...",
    "Designing structure...",
    "Calculating physics...",
    "Mixing colors...",
    "Assembling geometry...",
    "Applying polish..."
];

const PALETTE = [
    COLORS.DARK, COLORS.LIGHT, COLORS.WHITE, COLORS.GOLD,
    COLORS.BLACK, COLORS.WOOD, COLORS.GREEN, COLORS.TALON,
    0xFF5555, 0x55FF55, 0x5555FF, 0xFFAA00
];

export const UIOverlay: React.FC<UIOverlayProps> = ({
  voxelCount,
  appState,
  currentBaseModel,
  customBuilds,
  customRebuilds,
  isAutoRotate,
  isInfoVisible,
  isGenerating,
  isWireframe,

  isEditMode,
  activeTool,
  activeColor,
  symmetryMode,
  onSetEditMode,
  onSetTool,
  onSetColor,
  onSetSymmetry,

  keyframes,
  currentFrameIndex,
  isAnimating,
  isLooping,
  onCaptureKeyframe,
  onDeleteKeyframe,
  onJumpToKeyframe,
  onTogglePlayback,
  onToggleLoop,
  onPromptAnimate,

  onDismantle,
  onRebuild,
  onNewScene,
  onSelectCustomBuild,
  onSelectCustomRebuild,
  onPromptCreate,
  onPromptMorph,
  onShowJson,
  onImportJson,
  onToggleRotation,
  onToggleWireframe,
  onToggleInfo
}) => {
  const isStable = appState === AppState.STABLE;
  const isDismantling = appState === AppState.DISMANTLING;
  const [loadingMsgIndex, setLoadingMsgIndex] = useState(0);

  useEffect(() => {
    if (isGenerating) {
        const interval = setInterval(() => {
            setLoadingMsgIndex((prev) => (prev + 1) % LOADING_MESSAGES.length);
        }, 2000);
        return () => clearInterval(interval);
    } else {
        setLoadingMsgIndex(0);
    }
  }, [isGenerating]);

  const isEagle = currentBaseModel === 'Eagle';

  return (
    <div className="absolute top-0 left-0 w-full h-full pointer-events-none select-none">

      {/* --- Top Bar --- */}
      <div className="absolute top-4 left-4 right-4 flex justify-between items-start">
        <div className="pointer-events-auto flex flex-col gap-2">
            <DropdownMenu 
                icon={<FolderOpen size={20} />}
                label="Builds"
                color="indigo"
            >
                <div className="px-2 py-1 text-xs font-bold text-slate-400 uppercase tracking-wider">NEW BUILDS</div>
                <DropdownItem onClick={() => onNewScene('Eagle')} icon={<Bird size={16}/>} label="Eagle" />
                <DropdownItem onClick={onPromptCreate} icon={<Wand2 size={16}/>} label="New build" highlight />
                <div className="h-px bg-slate-100 my-1" />

                {customBuilds.length > 0 && (
                    <>
                        <div className="px-2 py-1 text-xs font-bold text-slate-400 uppercase tracking-wider">YOUR CREATIONS</div>
                        {customBuilds.map((model, idx) => (
                            <DropdownItem key={`build-${idx}`} onClick={() => onSelectCustomBuild(model)} icon={<History size={16}/>} label={model.name} truncate />
                        ))}
                        <div className="h-px bg-slate-100 my-1" />
                    </>
                )}
                <DropdownItem onClick={onImportJson} icon={<FileJson size={16}/>} label="Import JSON" />
            </DropdownMenu>

            <div className="flex items-center gap-3 px-4 py-2 bg-white/90 backdrop-blur-sm shadow-sm rounded-xl border border-slate-200 text-slate-500 font-bold w-fit mt-2">
                <div className="bg-blue-100 p-1.5 rounded-lg text-blue-600">
                    <Box size={16} strokeWidth={3} />
                </div>
                <div className="flex flex-col leading-none">
                    <span className="text-[10px] uppercase tracking-wider opacity-60">Voxels</span>
                    <span className="text-lg text-slate-800 font-extrabold font-mono">{voxelCount}</span>
                </div>
            </div>
        </div>

        <div className="pointer-events-auto flex gap-2">
            <TactileButton
                onClick={() => onSetEditMode(!isEditMode)}
                color={isEditMode ? 'emerald' : 'slate'}
                icon={<Paintbrush size={18} strokeWidth={2.5} />}
                label="Edit"
                compact
            />
            <TactileButton
                onClick={onToggleWireframe}
                color={isWireframe ? 'amber' : 'slate'}
                icon={<Grid size={18} strokeWidth={2.5} />}
                label="Wireframe"
                compact
            />
            <TactileButton
                onClick={onToggleInfo}
                color={isInfoVisible ? 'indigo' : 'slate'}
                icon={<Info size={18} strokeWidth={2.5} />}
                label="Info"
                compact
            />
            <TactileButton
                onClick={onToggleRotation}
                color={isAutoRotate ? 'sky' : 'slate'}
                icon={isAutoRotate ? <Pause size={18} fill="currentColor" /> : <Play size={18} fill="currentColor" />}
                label={isAutoRotate ? "Pause" : "Play"}
                compact
            />
            <TactileButton
                onClick={onShowJson}
                color="slate"
                icon={<Code2 size={18} strokeWidth={2.5} />}
                label="Share"
            />
        </div>
      </div>

      {/* --- Edit Sidebar --- */}
      {isEditMode && isStable && (
        <div className="absolute left-4 top-40 pointer-events-auto flex flex-col gap-4 animate-in slide-in-from-left-10 duration-300">
            {/* Tool Selection */}
            <div className="bg-white/90 backdrop-blur-sm p-2 rounded-2xl shadow-xl border border-slate-200 flex flex-col gap-2">
                <IconButton 
                    active={activeTool === EditTool.BRUSH} 
                    onClick={() => onSetTool(EditTool.BRUSH)} 
                    icon={<Paintbrush size={20} />} 
                    color="sky" 
                />
                <IconButton 
                    active={activeTool === EditTool.ERASER} 
                    onClick={() => onSetTool(EditTool.ERASER)} 
                    icon={<Eraser size={20} />} 
                    color="rose" 
                />
            </div>

            {/* Symmetry Toggle */}
            <div className="bg-white/90 backdrop-blur-sm p-2 rounded-2xl shadow-xl border border-slate-200 flex flex-col gap-2">
                <div className="text-[10px] font-black text-slate-400 text-center uppercase tracking-tighter mb-1">Mirror</div>
                <IconButton 
                    active={symmetryMode === SymmetryMode.NONE} 
                    onClick={() => onSetSymmetry(SymmetryMode.NONE)} 
                    icon={<div className="text-xs font-bold">OFF</div>} 
                    color="slate" 
                />
                <IconButton 
                    active={symmetryMode === SymmetryMode.X} 
                    onClick={() => onSetSymmetry(SymmetryMode.X)} 
                    icon={<div className="text-sm font-black">X</div>} 
                    color="indigo" 
                />
                <IconButton 
                    active={symmetryMode === SymmetryMode.Z} 
                    onClick={() => onSetSymmetry(SymmetryMode.Z)} 
                    icon={<div className="text-sm font-black">Z</div>} 
                    color="indigo" 
                />
            </div>

            {/* Color Palette */}
            <div className="bg-white/90 backdrop-blur-sm p-3 rounded-2xl shadow-xl border border-slate-200 grid grid-cols-2 gap-2">
