              <div className="bg-white/80 backdrop-blur-xl border border-slate-200 shadow-2xl rounded-[2rem] p-3 flex items-center gap-4 min-w-[300px]">
                  {/* Playback Controls */}
                  <div className="flex items-center gap-2 pr-4 border-r border-slate-100">
                      <button 
                        onClick={onTogglePlayback}
                        disabled={keyframes.length === 0}
                        className={`w-12 h-12 rounded-2xl flex items-center justify-center transition-all active:scale-90 disabled:opacity-30 ${isAnimating ? 'bg-amber-100 text-amber-600 shadow-inner' : 'bg-indigo-600 text-white shadow-lg shadow-indigo-200'}`}
                      >
                        {isAnimating ? <Pause size={24} fill="currentColor" /> : <Play size={24} className="ml-1" fill="currentColor" />}
                      </button>
                      <button 
                        onClick={onToggleLoop}
                        className={`p-2 rounded-xl transition-colors ${isLooping ? 'text-emerald-500 bg-emerald-50' : 'text-slate-300'}`}
                        title="Loop Animation"
                      >
                        <Repeat size={18} strokeWidth={3} />
                      </button>
                  </div>

                  {/* Timeline Strip */}
                  <div className="flex-1 flex items-center gap-2 overflow-x-auto max-w-[400px] py-1 px-1 scrollbar-hide">
                      {keyframes.length === 0 ? (
                          <div className="text-slate-400 font-bold text-sm px-4 flex items-center gap-2">
                              <Film size={16} />
                              Empty Timeline
                          </div>
                      ) : (
                        keyframes.map((kf, idx) => (
                            <div key={kf.id} className="relative group shrink-0">
                                <button 
                                    onClick={() => onJumpToKeyframe(idx)}
                                    className={`w-14 h-14 rounded-xl border-2 transition-all overflow-hidden flex flex-col items-center justify-center gap-1 ${currentFrameIndex === idx ? 'border-indigo-500 bg-indigo-50 shadow-md ring-2 ring-indigo-200' : 'border-slate-100 bg-slate-50 hover:border-slate-300'}`}
                                >
                                    <span className={`text-[10px] font-black ${currentFrameIndex === idx ? 'text-indigo-600' : 'text-slate-400'}`}>F{idx+1}</span>
                                    <div className="w-6 h-1.5 bg-slate-300 rounded-full" />
                                </button>
                                <button 
                                    onClick={(e) => { e.stopPropagation(); onDeleteKeyframe(kf.id); }}
                                    className="absolute -top-1 -right-1 w-5 h-5 bg-rose-500 text-white rounded-full flex items-center justify-center opacity-0 group-hover:opacity-100 transition-opacity hover:bg-rose-600 shadow-sm"
                                >
                                    <Trash2 size={12} strokeWidth={3} />
                                </button>
                            </div>
