import React, { useState, useEffect, useRef } from 'react';
import { AppState, SavedModel, VoxelData, EditTool, SymmetryMode, VoxelKeyframe } from '../types';
import { Box, Bird, Cat, Rabbit, Users, Code2, Wand2, Hammer, FolderOpen, ChevronUp, FileJson, History, Play, Pause, Info, Wrench, Loader2, Paintbrush, Eraser, Layers, RotateCcw, Film, Plus, Trash2, Repeat, SkipForward, Sparkles, Grid, Apple, MessageSquare } from 'lucide-react';
import { COLORS } from '../utils/voxelConstants';

interface UIOverlayProps {
  voxelCount: number;
  appState: AppState;
  currentBaseModel: string;
  customBuilds: SavedModel[];
  customRebuilds: SavedModel[];
  isAutoRotate: boolean;
  isInfoVisible: boolean;
  isGenerating: boolean;
  isWireframe: boolean;

  // Edit Mode Props
  isEditMode: boolean;
  activeTool: EditTool;
  activeColor: number;
  symmetryMode: SymmetryMode;
  onSetEditMode: (val: boolean) => void;
  onSetTool: (tool: EditTool) => void;
  onSetColor: (color: number) => void;
  onSetSymmetry: (mode: SymmetryMode) => void;

  // Animation Props
  keyframes: VoxelKeyframe[];
  currentFrameIndex: number;
  isAnimating: boolean;
  isLooping: boolean;
  onCaptureKeyframe: () => void;
  onDeleteKeyframe: (id: string) => void;
  onJumpToKeyframe: (index: number) => void;
  onTogglePlayback: () => void;
  onToggleLoop: () => void;
  onPromptAnimate: () => void;

  onDismantle: () => void;
  onDrop: () => void;
  onRebuild: (type: 'Eagle' | 'Cat' | 'Rabbit' | 'Twins') => void;
  onNewScene: (type: 'Eagle') => void;
  onSelectCustomBuild: (model: SavedModel) => void;
  onSelectCustomRebuild: (model: SavedModel) => void;
  onPromptCreate: () => void;
  onPromptMorph: () => void;
  onShowJson: () => void;
  onImportJson: () => void;
  onToggleRotation: () => void;
  onToggleWireframe: () => void;
  onToggleInfo: () => void;

  onToggleChat: () => void;
  isChatOpen: boolean;
}

const LOADING_MESSAGES = [
    "Crafting voxels...",
    "Designing structure...",
    "Calculating physics...",
    "Mixing colors...",
    "Assembling geometry...",
    "Applying polish..."
];

const PALETTE = [
    COLORS.DARK, COLORS.LIGHT, COLORS.WHITE, COLORS.GOLD,
    COLORS.BLACK, COLORS.WOOD, COLORS.GREEN, COLORS.TALON,
    0xFF5555, 0x55FF55, 0x5555FF, 0xFFAA00
];

export const UIOverlay: React.FC<UIOverlayProps> = ({
  voxelCount,
  appState,
  currentBaseModel,
  customBuilds,
  customRebuilds,
  isAutoRotate,
  isInfoVisible,
  isGenerating,
  isWireframe,

  isEditMode,
  activeTool,
  activeColor,
  symmetryMode,
  onSetEditMode,
  onSetTool,
  onSetColor,
  onSetSymmetry,

  keyframes,
  currentFrameIndex,
  isAnimating,
  isLooping,
  onCaptureKeyframe,
  onDeleteKeyframe,
  onJumpToKeyframe,
  onTogglePlayback,
  onToggleLoop,
  onPromptAnimate,

  onDismantle,
  onDrop,
  onRebuild,
  onNewScene,
  onSelectCustomBuild,
  onSelectCustomRebuild,
  onPromptCreate,
  onPromptMorph,
  onShowJson,
  onImportJson,
  onToggleRotation,
  onToggleWireframe,
  onToggleInfo,

  onToggleChat,
  isChatOpen
}) => {
  const isStable = appState === AppState.STABLE;
  const isDismantling = appState === AppState.DISMANTLING;
  const [loadingMsgIndex, setLoadingMsgIndex] = useState(0);

  useEffect(() => {
    if (isGenerating) {
        const interval = setInterval(() => {
            setLoadingMsgIndex((prev) => (prev + 1) % LOADING_MESSAGES.length);
        }, 2000);
        return () => clearInterval(interval);
    } else {
        setLoadingMsgIndex(0);
    }
  }, [isGenerating]);

  const isEagle = currentBaseModel === 'Eagle';

  return (
    <div className="absolute top-0 left-0 w-full h-full pointer-events-none select-none">

      {/* --- Top Bar --- */}
      <div className="absolute top-4 left-4 right-4 flex justify-between items-start">
        <div className="pointer-events-auto flex flex-col gap-2">
            <DropdownMenu 
                icon={<FolderOpen size={20} />}
                label="Builds"
                color="indigo"
            >
                <div className="px-2 py-1 text-xs font-bold text-slate-400 uppercase tracking-wider">NEW BUILDS</div>
                <DropdownItem onClick={() => onNewScene('Eagle')} icon={<Bird size={16}/>} label="Eagle" />
                <DropdownItem onClick={onPromptCreate} icon={<Wand2 size={16}/>} label="New build" highlight />
                <div className="h-px bg-slate-100 my-1" />

                {customBuilds.length > 0 && (
                    <>
                        <div className="px-2 py-1 text-xs font-bold text-slate-400 uppercase tracking-wider">YOUR CREATIONS</div>
                        {customBuilds.map((model, idx) => (
                            <DropdownItem key={`build-${idx}`} onClick={() => onSelectCustomBuild(model)} icon={<History size={16}/>} label={model.name} truncate />
                        ))}
                        <div className="h-px bg-slate-100 my-1" />
                    </>
                )}
                <DropdownItem onClick={onImportJson} icon={<FileJson size={16}/>} label="Import JSON" />
            </DropdownMenu>

            <div className="flex items-center gap-3 px-4 py-2 bg-white/90 backdrop-blur-sm shadow-sm rounded-xl border border-slate-200 text-slate-500 font-bold w-fit mt-2">
                <div className="bg-blue-100 p-1.5 rounded-lg text-blue-600">
                    <Box size={16} strokeWidth={3} />
                </div>
                <div className="flex flex-col leading-none">
                    <span className="text-[10px] uppercase tracking-wider opacity-60">Voxels</span>
                    <span className="text-lg text-slate-800 font-extrabold font-mono">{voxelCount}</span>
                </div>
            </div>
        </div>

        <div className="pointer-events-auto flex gap-2">
            <TactileButton
                onClick={() => onSetEditMode(!isEditMode)}
                color={isEditMode ? 'emerald' : 'slate'}
                icon={<Paintbrush size={18} strokeWidth={2.5} />}
                label="Edit"
                compact
            />
            {isStable ? (
                <TactileButton
                    onClick={onDrop}
                    color="rose"
                    icon={<Apple size={18} strokeWidth={2.5} />}
                    label="Gravity"
                    compact
                />
            ) : (
                 <TactileButton
                    onClick={() => {}} // Placeholder or maybe Reset
                    color="slate"
                    icon={<Apple size={18} strokeWidth={2.5} className="opacity-30" />}
                    label="Gravity"
                    compact
                />
            )}
            <TactileButton
                onClick={onToggleWireframe}
                color={isWireframe ? 'amber' : 'slate'}
                icon={<Grid size={18} strokeWidth={2.5} />}
                label="Wireframe"
                compact
            />
            <TactileButton
                onClick={onToggleInfo}
                color={isInfoVisible ? 'indigo' : 'slate'}
                icon={<Info size={18} strokeWidth={2.5} />}
                label="Info"
                compact
            />
            <TactileButton
                onClick={onToggleRotation}
                color={isAutoRotate ? 'sky' : 'slate'}
                icon={isAutoRotate ? <Pause size={18} fill="currentColor" /> : <Play size={18} fill="currentColor" />}
                label={isAutoRotate ? "Pause" : "Play"}
                compact
            />
            <TactileButton
                onClick={onToggleChat}
                color={isChatOpen ? 'indigo' : 'slate'}
                icon={<MessageSquare size={18} strokeWidth={2.5} />}
                label="Chat"
                compact
            />
            <TactileButton
                onClick={onShowJson}
                color="slate"
                icon={<Code2 size={18} strokeWidth={2.5} />}
                label="Share"
            />
        </div>
      </div>

      {/* --- Edit Sidebar --- */}
      {isEditMode && isStable && (
        <div className="absolute left-4 top-40 pointer-events-auto flex flex-col gap-4 animate-in slide-in-from-left-10 duration-300">
            {/* Tool Selection */}
            <div className="bg-white/90 backdrop-blur-sm p-2 rounded-2xl shadow-xl border border-slate-200 flex flex-col gap-2">
                <IconButton 
                    active={activeTool === EditTool.BRUSH} 
                    onClick={() => onSetTool(EditTool.BRUSH)} 
                    icon={<Paintbrush size={20} />} 
                    color="sky" 
                />
                <IconButton 
                    active={activeTool === EditTool.ERASER} 
                    onClick={() => onSetTool(EditTool.ERASER)} 
                    icon={<Eraser size={20} />} 
                    color="rose" 
                />
            </div>

            {/* Symmetry Toggle */}
            <div className="bg-white/90 backdrop-blur-sm p-2 rounded-2xl shadow-xl border border-slate-200 flex flex-col gap-2">
                <div className="text-[10px] font-black text-slate-400 text-center uppercase tracking-tighter mb-1">Mirror</div>
                <IconButton 
                    active={symmetryMode === SymmetryMode.NONE} 
                    onClick={() => onSetSymmetry(SymmetryMode.NONE)} 
                    icon={<div className="text-xs font-bold">OFF</div>} 
                    color="slate" 
                />
                <IconButton 
                    active={symmetryMode === SymmetryMode.X} 
                    onClick={() => onSetSymmetry(SymmetryMode.X)} 
                    icon={<div className="text-sm font-black">X</div>} 
                    color="indigo" 
                />
                <IconButton 
                    active={symmetryMode === SymmetryMode.Z} 
                    onClick={() => onSetSymmetry(SymmetryMode.Z)} 
                    icon={<div className="text-sm font-black">Z</div>} 
                    color="indigo" 
                />
            </div>

            {/* Color Palette */}
            <div className="bg-white/90 backdrop-blur-sm p-3 rounded-2xl shadow-xl border border-slate-200 grid grid-cols-2 gap-2">
                {PALETTE.map((color) => (
                    <button
                        key={color}
                        onClick={() => onSetColor(color)}
                        className={`w-8 h-8 rounded-full border-2 transition-transform hover:scale-110 active:scale-95 ${activeColor === color ? 'border-indigo-500 scale-110 shadow-lg' : 'border-black/5'}`}
                        style={{ backgroundColor: `#${color.toString(16).padStart(6, '0')}` }}
                    />
                ))}
            </div>
        </div>
      )}

      {/* --- Choreographer Timeline --- */}
      {isStable && !isEditMode && (
          <div className="absolute bottom-8 left-8 pointer-events-auto flex flex-col items-start gap-3 animate-in slide-in-from-left-5 duration-500">
              <div className="bg-white/80 backdrop-blur-xl border border-slate-200 shadow-2xl rounded-[2rem] p-3 flex items-center gap-4 min-w-[300px]">
                  {/* Playback Controls */}
                  <div className="flex items-center gap-2 pr-4 border-r border-slate-100">
                      <button 
                        onClick={onTogglePlayback}
                        disabled={keyframes.length === 0}
                        className={`w-12 h-12 rounded-2xl flex items-center justify-center transition-all active:scale-90 disabled:opacity-30 ${isAnimating ? 'bg-amber-100 text-amber-600 shadow-inner' : 'bg-indigo-600 text-white shadow-lg shadow-indigo-200'}`}
                      >
                        {isAnimating ? <Pause size={24} fill="currentColor" /> : <Play size={24} className="ml-1" fill="currentColor" />}
                      </button>
                      <button 
                        onClick={onToggleLoop}
                        className={`p-2 rounded-xl transition-colors ${isLooping ? 'text-emerald-500 bg-emerald-50' : 'text-slate-300'}`}
                        title="Loop Animation"
                      >
                        <Repeat size={18} strokeWidth={3} />
                      </button>
                  </div>

                  {/* Timeline Strip */}
                  <div className="flex-1 flex items-center gap-2 overflow-x-auto max-w-[400px] py-1 px-1 scrollbar-hide">
                      {keyframes.length === 0 ? (
                          <div className="text-slate-400 font-bold text-sm px-4 flex items-center gap-2">
                              <Film size={16} />
                              Empty Timeline
                          </div>
                      ) : (
                        keyframes.map((kf, idx) => (
                            <div key={kf.id} className="relative group shrink-0">
                                <button 
                                    onClick={() => onJumpToKeyframe(idx)}
                                    className={`w-14 h-14 rounded-xl border-2 transition-all overflow-hidden flex flex-col items-center justify-center gap-1 ${currentFrameIndex === idx ? 'border-indigo-500 bg-indigo-50 shadow-md ring-2 ring-indigo-200' : 'border-slate-100 bg-slate-50 hover:border-slate-300'}`}
                                >
                                    <span className={`text-[10px] font-black ${currentFrameIndex === idx ? 'text-indigo-600' : 'text-slate-400'}`}>F{idx+1}</span>
                                    <div className="w-6 h-1.5 bg-slate-300 rounded-full" />
                                </button>
                                <button 
                                    onClick={(e) => { e.stopPropagation(); onDeleteKeyframe(kf.id); }}
                                    className="absolute -top-1 -right-1 w-5 h-5 bg-rose-500 text-white rounded-full flex items-center justify-center opacity-0 group-hover:opacity-100 transition-opacity hover:bg-rose-600 shadow-sm"
                                >
                                    <Trash2 size={12} strokeWidth={3} />
                                </button>
                            </div>
                        ))
                      )}
                  </div>

                  {/* Add Frame / Generate */}
                  <div className="pl-4 border-l border-slate-100 flex gap-2">
                      <button 
                        onClick={onCaptureKeyframe}
                        title="Capture current pose"
                        className="w-12 h-12 rounded-2xl bg-slate-100 text-slate-500 hover:bg-slate-200 hover:text-slate-700 flex items-center justify-center transition-all active:scale-95 group"
                      >
                        <Plus size={24} strokeWidth={3} className="group-hover:scale-110 transition-transform" />
                      </button>

                      <button 
                        onClick={onPromptAnimate}
                        title="Generate AI Animation"
                        className="w-12 h-12 rounded-2xl bg-gradient-to-br from-violet-500 to-fuchsia-500 text-white shadow-lg shadow-violet-500/30 flex items-center justify-center transition-all active:scale-95 hover:brightness-110 group"
                      >
                        <Sparkles size={20} strokeWidth={2.5} className="group-hover:rotate-12 transition-transform" />
                      </button>
                  </div>
              </div>
              <div className="text-[10px] font-black text-slate-400 uppercase tracking-widest bg-white/60 px-3 py-1 rounded-full backdrop-blur-sm shadow-sm">
                  Choreographer Sequence
              </div>
          </div>
      )}

      {/* --- Loading Indicator --- */}
      {isGenerating && (
          <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 z-50 animate-in fade-in zoom-in duration-300">
              <div className="bg-white/90 backdrop-blur-md border-2 border-indigo-100 px-8 py-6 rounded-3xl shadow-2xl flex flex-col items-center gap-4 min-w-[280px]">
                  <Loader2 size={48} className="text-indigo-500 animate-spin" />
                  <div className="text-center">
                      <h3 className="text-lg font-extrabold text-slate-800">Gemini is Building...</h3>
                      <p className="text-slate-500 font-bold text-sm">{LOADING_MESSAGES[loadingMsgIndex]}</p>
                  </div>
              </div>
          </div>
      )}

      {/* --- Bottom Controls --- */}
      <div className="absolute bottom-8 left-0 w-full flex justify-center items-end pointer-events-none">
        <div className="pointer-events-auto transition-all duration-500">
            {isStable && !isEditMode && (
                 <div className="animate-in slide-in-from-bottom-10 fade-in duration-300">
                     <BigActionButton onClick={onDismantle} icon={<Hammer size={32} strokeWidth={2.5} />} label="BREAK" color="rose" />
                 </div>
            )}

            {isDismantling && !isGenerating && (
                <div className="flex items-end gap-4 animate-in slide-in-from-bottom-10 fade-in duration-300">
                     <DropdownMenu icon={<Wrench size={24} />} label="Rebuild" color="emerald" direction="up" big>
                        <div className="px-2 py-1 text-xs font-bold text-slate-400 uppercase tracking-wider">REBUILD</div>
                        {isEagle && (
                            <>
                                <DropdownItem onClick={() => onRebuild('Cat')} icon={<Cat size={18}/>} label="Cat" />
                                <DropdownItem onClick={() => onRebuild('Rabbit')} icon={<Rabbit size={18}/>} label="Rabbit" />
                                <DropdownItem onClick={() => onRebuild('Twins')} icon={<Users size={18}/>} label="Eagles x2" />
                                <div className="h-px bg-slate-100 my-1" />
                            </>
                        )}
                        {customRebuilds.map((model, idx) => (
                            <DropdownItem key={`rebuild-${idx}`} onClick={() => onSelectCustomRebuild(model)} icon={<History size={18}/>} label={model.name} truncate />
                        ))}
                        <DropdownItem onClick={onPromptMorph} icon={<Wand2 size={18}/>} label="New rebuild" highlight />
                     </DropdownMenu>
                </div>
            )}
        </div>
      </div>
    </div>
  );
};

const IconButton: React.FC<{active: boolean, onClick: () => void, icon: React.ReactNode, color: string}> = ({ active, onClick, icon, color }) => {
    const colorClasses: any = {
        sky: 'bg-sky-500 shadow-sky-700',
        rose: 'bg-rose-500 shadow-rose-700',
        indigo: 'bg-indigo-500 shadow-indigo-700',
        slate: 'bg-slate-400 shadow-slate-600'
    };
    return (
        <button 
            onClick={onClick}
            className={`w-10 h-10 rounded-xl flex items-center justify-center transition-all border-b-[4px] active:border-b-0 active:translate-y-[4px] ${active ? `${colorClasses[color]} text-white border-black/20` : 'bg-slate-100 text-slate-400 border-slate-200 shadow-none'}`}
        >
            {icon}
        </button>
    );
};

interface TactileButtonProps {
  onClick: () => void;
  icon: React.ReactNode;
  label: string;
  color: 'slate' | 'rose' | 'sky' | 'emerald' | 'amber' | 'indigo';
  compact?: boolean;
}

const TactileButton: React.FC<TactileButtonProps> = ({ onClick, icon, label, color, compact }) => {
  const colorStyles = {
    slate:   'bg-slate-200 text-slate-600 shadow-slate-300 hover:bg-slate-300',
    rose:    'bg-rose-500 text-white shadow-rose-700 hover:bg-rose-600',
    sky:     'bg-sky-500 text-white shadow-sky-700 hover:bg-sky-600',
    emerald: 'bg-emerald-500 text-white shadow-emerald-700 hover:bg-emerald-600',
    amber:   'bg-amber-400 text-amber-900 shadow-amber-600 hover:bg-amber-500',
    indigo:  'bg-indigo-500 text-white shadow-indigo-700 hover:bg-indigo-600',
