    COLORS.BLUE, COLORS.RED, COLORS.GLASS, COLORS.GREY
];

export const UIOverlay: React.FC<UIOverlayProps> = ({
  voxelCount,
  appState,
  currentBaseModel,
  customBuilds,
  customRebuilds,
  isAutoRotate,
  isInfoVisible,
  isGenerating,
  isWireframe,

  isEditMode,
  activeTool,
  activeColor,
  symmetryMode,
  onSetEditMode,
  onSetTool,
