const radius = 4;
const wall = 3;         // shell thickness
const length = 14;
const startX = -7;

// Barrel shell (thick hollow cylinder)
for (let x = 0; x < length; x++) {
  const px = startX + x;

  for (let y = -radius; y <= radius; y++) {
    for (let z = -radius; z <= radius; z++) {
      const d = Math.sqrt(y*y + z*z);
      if (d <= radius && d >= radius - wall) {
        v.push({ x: px, y: 8 + y, z, c: C_METAL });
      }
    }
  }
}

// End caps
for (let y = -radius+1; y <= radius-1; y++) {
  for (let z = -radius+1; z <= radius-1; z++) {
    if (Math.sqrt(y*y+z*z) <= radius-1) {
      v.push({ x: startX-1, y: 8+y, z, c: C_DARK_METAL });
      v.push({ x: startX+length, y: 8+y, z, c: C_DARK_METAL });
    }
  }
}

// Axle
for (let x = startX-2; x <= startX+length+1; x++) {
  v.push({ x, y: 8, z: 0, c: C_PIPE });
}

// Internal lifter fins
for (let x = startX+1; x < startX+length-1; x++) {
