                                >
                                    <span className={`text-[10px] font-black ${currentFrameIndex === idx ? 'text-indigo-600' : 'text-slate-400'}`}>F{idx+1}</span>
                                    <div className="w-6 h-1.5 bg-slate-300 rounded-full" />
                                </button>
                                <button 
