                                    className="absolute -top-1 -right-1 w-5 h-5 bg-rose-500 text-white rounded-full flex items-center justify-center opacity-0 group-hover:opacity-100 transition-opacity hover:bg-rose-600 shadow-sm"
                                >
                                    <Trash2 size={12} strokeWidth={3} />
                                </button>
                            </div>
                        ))
                      )}
                  </div>

                  {/* Add Frame / Generate */}
                  <div className="pl-4 border-l border-slate-100 flex gap-2">
                      <button 
                        onClick={onCaptureKeyframe}
                        title="Capture current pose"
                        className="w-12 h-12 rounded-2xl bg-slate-100 text-slate-500 hover:bg-slate-200 hover:text-slate-700 flex items-center justify-center transition-all active:scale-95 group"
                      >
                        <Plus size={24} strokeWidth={3} className="group-hover:scale-110 transition-transform" />
                      </button>

                      <button 
                        onClick={onPromptAnimate}
                        title="Generate AI Animation"
                        className="w-12 h-12 rounded-2xl bg-gradient-to-br from-violet-500 to-fuchsia-500 text-white shadow-lg shadow-violet-500/30 flex items-center justify-center transition-all active:scale-95 hover:brightness-110 group"
                      >
                        <Sparkles size={20} strokeWidth={2.5} className="group-hover:rotate-12 transition-transform" />
                      </button>
                  </div>
              </div>
              <div className="text-[10px] font-black text-slate-400 uppercase tracking-widest bg-white/60 px-3 py-1 rounded-full backdrop-blur-sm shadow-sm">
                  Choreographer Sequence
              </div>
          </div>
      )}

      {/* --- Loading Indicator --- */}
      {isGenerating && (
          <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 z-50 animate-in fade-in zoom-in duration-300">
              <div className="bg-white/90 backdrop-blur-md border-2 border-indigo-100 px-8 py-6 rounded-3xl shadow-2xl flex flex-col items-center gap-4 min-w-[280px]">
                  <Loader2 size={48} className="text-indigo-500 animate-spin" />
                  <div className="text-center">
                      <h3 className="text-lg font-extrabold text-slate-800">Gemini is Building...</h3>
                      <p className="text-slate-500 font-bold text-sm">{LOADING_MESSAGES[loadingMsgIndex]}</p>
                  </div>
              </div>
          </div>
      )}

      {/* --- Bottom Controls --- */}
      <div className="absolute bottom-8 left-0 w-full flex justify-center items-end pointer-events-none">
        <div className="pointer-events-auto transition-all duration-500">
            {isStable && !isEditMode && (
                 <div className="animate-in slide-in-from-bottom-10 fade-in duration-300">
                     <BigActionButton onClick={onDismantle} icon={<Hammer size={32} strokeWidth={2.5} />} label="BREAK" color="rose" />
                 </div>
            )}

            {isDismantling && !isGenerating && (
                <div className="flex items-end gap-4 animate-in slide-in-from-bottom-10 fade-in duration-300">
                     <DropdownMenu icon={<Wrench size={24} />} label="Rebuild" color="emerald" direction="up" big>
                        <div className="px-2 py-1 text-xs font-bold text-slate-400 uppercase tracking-wider">REBUILD</div>
                        {isEagle && (
                            <>
                                <DropdownItem onClick={() => onRebuild('Cat')} icon={<Cat size={18}/>} label="Cat" />
                                <DropdownItem onClick={() => onRebuild('Rabbit')} icon={<Rabbit size={18}/>} label="Rabbit" />
                                <DropdownItem onClick={() => onRebuild('Twins')} icon={<Users size={18}/>} label="Eagles x2" />
                                <div className="h-px bg-slate-100 my-1" />
