];

// Heavy Plant blueprint generator (no React, no THREE)
export function generateHeavyPlantVoxels({ tailingsCount = 1000 } = {}) {
  const v = [...BASE_BLUEPRINT];

  const C_METAL = COLORS.METAL;
  const C_DARK_METAL = COLORS.DARK_METAL;
  const C_DIRT = COLORS.DIRT;
  const C_WATER = COLORS.WATER;
  const C_CAUTION = COLORS.CAUTION;
  const C_RED = COLORS.RED;
  const C_PIPE = COLORS.PIPE;

  // Chassis rails
  for (let x = -8; x <= 8; x++) {
    for (const z of [-4, 4]) {
      for (let y = 0; y <= 2; y++) v.push({ x, y, z, c: C_DARK_METAL });
    }
  }

  // Trommel drum (your original “skin” version)
  const radius = 4, length = 12, startX = -6;
  for (let i = 0; i < length; i++) {
    const px = startX + i;
    for (let angle = 0; angle < Math.PI * 2; angle += 0.4) {
      if ((i + Math.floor(angle * 5)) % 2 === 0) {
        v.push({
          x: px,
          y: Math.round(8 + Math.sin(angle) * radius),
          z: Math.round(Math.cos(angle) * radius),
          c: C_METAL
        });
      }
    }
  }

  // Intake hopper
  for (let y = 12; y < 18; y++) {
    const flare = y - 12;
    for (let x = 6 - flare; x <= 10 + flare; x++) {
      for (let z = -5 - flare; z <= 5 + flare; z++) {
        if (Math.abs(x - 8) === 2 + flare || Math.abs(z) === 5 + flare || y === 12) v.push({ x, y, z, c: C_METAL });
        if (y === 17 && z % 2 === 0) v.push({ x, y, z, c: C_DARK_METAL });
      }
    }
  }

  // Dual sluices (water + frame)
  [{ z: -6, a: 1 }, { z: 6, a: -1 }].forEach(p => {
    for (let i = 0; i < 10; i++) {
      for (let sx = -3; sx <= 3; sx++) {
        const sz = p.z + (i * p.a), sy = 6 - i * 0.4;
        v.push({ x: sx, y: Math.round(sy), z: sz, c: C_METAL });
        if (sx !== -3 && sx !== 3) v.push({ x: sx, y: Math.round(sy) + 1, z: sz, c: C_WATER });
      }
    }
  });

  // Engine room & stack
  for (let x = -14; x <= -9; x++)
    for (let z = -3; z <= 3; z++)
      for (let y = 0; y < 6; y++) v.push({ x, y, z, c: C_RED });

  for (let ey = 6; ey < 12; ey++) v.push({ x: -13, y: ey, z: 0, c: C_DARK_METAL });

  // Simple pipe
  for (let x = -10; x <= 6; x++) v.push({ x, y: 6, z: 2, c: C_PIPE });

  // Safety rails
  for (let x = -8; x <= 12; x++) {
    for (const z of [-6, 6]) {
      for (let ry = 8; ry <= 11; ry++) v.push({ x, y: ry, z, c: C_CAUTION });
    }
  }

  // Tailings pile (deterministic-ish: still random unless you seed Math.random)
  for (let i = 0; i < tailingsCount; i++) {
    const angle = Math.random() * Math.PI * 2;
    const dist = Math.pow(Math.random(), 0.7) * 18;
    v.push({
      x: Math.round(-20 + Math.cos(angle) * dist),
      y: Math.round(Math.max(0, 8 - dist * 0.5)),
      z: Math.round(Math.sin(angle) * dist),
      c: C_DIRT
    });
  }

  return v;
}

