         // Main Building Block (2 stories)
         const W = 8, D = 6;
         for(let y=0; y<9; y++) {
             for(let x=-W; x<=W; x++) {
                 for(let z=-D; z<=D; z++) {
                     // Foundation
                     if (y===0) { setBlock(map, x, Y, z, COLORS.DARK_GREY); continue; }

                     // Walls
                     if (x===-W || x===W || z===-D || z===D) {
