                         if ((y===3 || y===7) && Math.abs(x) < W-1 && Math.abs(z) < D-1) {
                             setBlock(map, x, Y+y, z, COLORS.GLASS);
                         } else {
                             setBlock(map, x, Y+y, z, COLORS.GREY);
                         }
                     }
                     // Floors
                     if (y===4 || y===8) setBlock(map, x, Y+y, z, COLORS.DARK_GREY);
                 }
             }
