         // Comms Tower on Roof
         const rY = Y+9;
         for(let y=0; y<8; y++) {
             setBlock(map, -4, rY+y, -3, COLORS.DARK_GREY);
             if (y%2===0) {
                 setBlock(map, -4, rY+y, -2, COLORS.GREY); // Ladder rungs?
             }
         }
         // Dish
         const dY = rY+5;
