         const HEIGHT = 28;
         for(let y=0; y<HEIGHT; y++) {
             const r = 2.5 - (y * 0.05); // Very slight taper
             const xMax = Math.ceil(r);
             for(let x=-xMax; x<=xMax; x++) {
                 for(let z=-xMax; z<=xMax; z++) {
                     if (x*x + z*z <= r*r) {
                         setBlock(map, x, Y+y, z, COLORS.WHITE);
                     }
                 }
             }
         }

