         const topY = Y + HEIGHT;
         const nacL = 6;
         for(let z=-2; z<nacL; z++) {
             for(let x=-2; x<=2; x++) {
                 for(let y=0; y<3; y++) {
                     setBlock(map, x, topY+y, z, COLORS.WHITE);
                 }
             }
         }
         // Detail on Nacelle
         setBlock(map, 0, topY+3, 2, COLORS.RED); // Aviation light

         // Rotor Hub
         const hubZ = -3;
         const hubY = topY + 1;
         generateSphere(map, 0, hubY, hubZ, 2, COLORS.GREY);

         // Blades (3 blades, 120 deg apart roughly)
