             const x = i * 0.866;
             const y = -i * 0.5;
             setBlock(map, x, hubY+y, hubZ, COLORS.WHITE);
             setBlock(map, x, hubY+y, hubZ+0.5, COLORS.WHITE);
         }

         return Array.from(map.values());
    },

