    "Crafting voxels...",
    "Designing structure...",
    "Calculating physics...",
    "Mixing colors...",
    "Assembling geometry...",
    "Applying polish..."
];

const PALETTE = [
    COLORS.DARK, COLORS.LIGHT, COLORS.WHITE, COLORS.GOLD,
    COLORS.BLACK, COLORS.WOOD, COLORS.GREEN, COLORS.TALON,
    COLORS.BLUE, COLORS.RED, COLORS.GLASS, COLORS.GREY
];

export const UIOverlay: React.FC<UIOverlayProps> = ({
  voxelCount,
  appState,
  currentBaseModel,
  customBuilds,
  customRebuilds,
  isAutoRotate,
  isInfoVisible,
  isGenerating,
  isWireframe,

  isEditMode,
  activeTool,
  activeColor,
  symmetryMode,
  onSetEditMode,
  onSetTool,
  onSetColor,
  onSetSymmetry,

  keyframes,
  currentFrameIndex,
  isAnimating,
  isLooping,
  onCaptureKeyframe,
  onDeleteKeyframe,
  onJumpToKeyframe,
  onTogglePlayback,
  onToggleLoop,
  onPromptAnimate,

  onDismantle,
  onDrop,
  onRebuild,
  onNewScene,
  onSelectCustomBuild,
  onSelectCustomRebuild,
  onPromptCreate,
  onPromptMorph,
  onShowJson,
  onImportJson,
  onToggleRotation,
  onToggleWireframe,
  onToggleInfo,

  onToggleChat,
