import React, { useState, useEffect, useRef } from 'react';
import { AppState, SavedModel, VoxelData, EditTool, SymmetryMode, VoxelKeyframe } from '../types';
import { Box, Bird, Cat, Rabbit, Users, Code2, Wand2, Hammer, FolderOpen, ChevronUp, FileJson, History, Play, Pause, Info, Wrench, Loader2, Paintbrush, Eraser, Layers, RotateCcw, Film, Plus, Trash2, Repeat, SkipForward, Sparkles, Grid, Apple, MessageSquare, Factory, Home, Fan, Sun, Shield, Gem, Trees, Droplets, Building2 } from 'lucide-react';
