    COLORS.BLACK, COLORS.WOOD, COLORS.GREEN, COLORS.TALON,
    COLORS.BLUE, COLORS.RED, COLORS.GLASS, COLORS.GREY
];

export const UIOverlay: React.FC<UIOverlayProps> = ({
  voxelCount,
  appState,
  currentBaseModel,
  customBuilds,
  customRebuilds,
  isAutoRotate,
  isInfoVisible,
  isGenerating,
  isWireframe,

  isEditMode,
  activeTool,
  activeColor,
  symmetryMode,
  onSetEditMode,
  onSetTool,
  onSetColor,
  onSetSymmetry,

  keyframes,
  currentFrameIndex,
  isAnimating,
  isLooping,
  onCaptureKeyframe,
  onDeleteKeyframe,
  onJumpToKeyframe,
  onTogglePlayback,
  onToggleLoop,
  onPromptAnimate,

  onDismantle,
  onDrop,
  onRebuild,
  onNewScene,
  onSelectCustomBuild,
  onSelectCustomRebuild,
  onPromptCreate,
  onPromptMorph,
  onShowJson,
