                    color="rose"
                    icon={<Apple size={18} strokeWidth={2.5} />}
                    label="Gravity"
                    compact
                />
            ) : (
                 <TactileButton
                    onClick={() => {}} // Placeholder or maybe Reset
                    color="slate"
                    icon={<Apple size={18} strokeWidth={2.5} className="opacity-30" />}
                    label="Gravity"
                    compact
                />
            )}
            <TactileButton
                onClick={onToggleWireframe}
                color={isWireframe ? 'amber' : 'slate'}
                icon={<Grid size={18} strokeWidth={2.5} />}
                label="Wireframe"
                compact
            />
            <TactileButton
                onClick={onToggleInfo}
                color={isInfoVisible ? 'indigo' : 'slate'}
                icon={<Info size={18} strokeWidth={2.5} />}
                label="Info"
                compact
            />
            <TactileButton
                onClick={onToggleRotation}
                color={isAutoRotate ? 'sky' : 'slate'}
                icon={isAutoRotate ? <Pause size={18} fill="currentColor" /> : <Play size={18} fill="currentColor" />}
                label={isAutoRotate ? "Pause" : "Play"}
                compact
            />
            <TactileButton
                onClick={onToggleChat}
                color={isChatOpen ? 'indigo' : 'slate'}
                icon={<MessageSquare size={18} strokeWidth={2.5} />}
                label="Chat"
                compact
            />
            <TactileButton
                onClick={onShowJson}
                color="slate"
                icon={<Code2 size={18} strokeWidth={2.5} />}
                label="Share"
            />
        </div>
      </div>

      {/* --- Edit Sidebar --- */}
      {isEditMode && isStable && (
        <div className="absolute left-4 top-40 pointer-events-auto flex flex-col gap-4 animate-in slide-in-from-left-10 duration-300">
            {/* Tool Selection */}
            <div className="bg-white/90 backdrop-blur-sm p-2 rounded-2xl shadow-xl border border-slate-200 flex flex-col gap-2">
                <IconButton 
                    active={activeTool === EditTool.BRUSH} 
                    onClick={() => onSetTool(EditTool.BRUSH)} 
                    icon={<Paintbrush size={20} />} 
                    color="sky" 
                />
                <IconButton 
                    active={activeTool === EditTool.ERASER} 
                    onClick={() => onSetTool(EditTool.ERASER)} 
                    icon={<Eraser size={20} />} 
                    color="rose" 
                />
            </div>

            {/* Symmetry Toggle */}
            <div className="bg-white/90 backdrop-blur-sm p-2 rounded-2xl shadow-xl border border-slate-200 flex flex-col gap-2">
                <div className="text-[10px] font-black text-slate-400 text-center uppercase tracking-tighter mb-1">Mirror</div>
                <IconButton 
                    active={symmetryMode === SymmetryMode.NONE} 
                    onClick={() => onSetSymmetry(SymmetryMode.NONE)} 
                    icon={<div className="text-xs font-bold">OFF</div>} 
                    color="slate" 
                />
                <IconButton 
                    active={symmetryMode === SymmetryMode.X} 
                    onClick={() => onSetSymmetry(SymmetryMode.X)} 
                    icon={<div className="text-sm font-black">X</div>} 
                    color="indigo" 
                />
                <IconButton 
                    active={symmetryMode === SymmetryMode.Z} 
                    onClick={() => onSetSymmetry(SymmetryMode.Z)} 
                    icon={<div className="text-sm font-black">Z</div>} 
                    color="indigo" 
                />
            </div>

            {/* Color Palette */}
            <div className="bg-white/90 backdrop-blur-sm p-3 rounded-2xl shadow-xl border border-slate-200 grid grid-cols-2 gap-2">
                {PALETTE.map((color) => (
                    <button
                        key={color}
                        onClick={() => onSetColor(color)}
                        className={`w-8 h-8 rounded-full border-2 transition-transform hover:scale-110 active:scale-95 ${activeColor === color ? 'border-indigo-500 scale-110 shadow-lg' : 'border-black/5'}`}
                        style={{ backgroundColor: `#${color.toString(16).padStart(6, '0')}` }}
                    />
                ))}
            </div>
        </div>
      )}

      {/* --- Choreographer Timeline --- */}
      {isStable && !isEditMode && (
          <div className="absolute bottom-8 left-8 pointer-events-auto flex flex-col items-start gap-3 animate-in slide-in-from-left-5 duration-500">
              <div className="bg-white/80 backdrop-blur-xl border border-slate-200 shadow-2xl rounded-[2rem] p-3 flex items-center gap-4 min-w-[300px]">
                  {/* Playback Controls */}
                  <div className="flex items-center gap-2 pr-4 border-r border-slate-100">
                      <button 
                        onClick={onTogglePlayback}
                        disabled={keyframes.length === 0}
                        className={`w-12 h-12 rounded-2xl flex items-center justify-center transition-all active:scale-90 disabled:opacity-30 ${isAnimating ? 'bg-amber-100 text-amber-600 shadow-inner' : 'bg-indigo-600 text-white shadow-lg shadow-indigo-200'}`}
                      >
                        {isAnimating ? <Pause size={24} fill="currentColor" /> : <Play size={24} className="ml-1" fill="currentColor" />}
                      </button>
                      <button 
                        onClick={onToggleLoop}
                        className={`p-2 rounded-xl transition-colors ${isLooping ? 'text-emerald-500 bg-emerald-50' : 'text-slate-300'}`}
                        title="Loop Animation"
                      >
                        <Repeat size={18} strokeWidth={3} />
                      </button>
                  </div>

                  {/* Timeline Strip */}
                  <div className="flex-1 flex items-center gap-2 overflow-x-auto max-w-[400px] py-1 px-1 scrollbar-hide">
                      {keyframes.length === 0 ? (
                          <div className="text-slate-400 font-bold text-sm px-4 flex items-center gap-2">
                              <Film size={16} />
                              Empty Timeline
                          </div>
                      ) : (
                        keyframes.map((kf, idx) => (
                            <div key={kf.id} className="relative group shrink-0">
                                <button 
                                    onClick={() => onJumpToKeyframe(idx)}
                                    className={`w-14 h-14 rounded-xl border-2 transition-all overflow-hidden flex flex-col items-center justify-center gap-1 ${currentFrameIndex === idx ? 'border-indigo-500 bg-indigo-50 shadow-md ring-2 ring-indigo-200' : 'border-slate-100 bg-slate-50 hover:border-slate-300'}`}
                                >
                                    <span className={`text-[10px] font-black ${currentFrameIndex === idx ? 'text-indigo-600' : 'text-slate-400'}`}>F{idx+1}</span>
